from itertools import count
from sympy import prime, integer_nthroot, integer_log
from oeis_sequences.OEISsequences import bisection
def A365308(n):
    def g(x):
        c = 2
        for i in count(2):
            c *= prime(i)
            if c>x:
                return  0 if i<3 else i-1
    def f(x): return n-1+x-sum(g(integer_nthroot(x,k)[0]) for k in range(2,integer_log(x,6)[0]+1))
    return bisection(f,n,n)

